import './health-meals-screen.css';
import { buildSectionPage } from '../../../utils/section-page.utils.js';
import {
    HEALTH_EVENTS,
    type AddIngredientEvent,
    type PickerCancelEvent,
} from '../health-events.js';
import {
    type MealWithIngredients,
    type NewMealWithIngredients,
} from '@motivation/shared';
import { HealthService } from '../../../services/health.service.js';
import type { ScreenComponent } from '../../../types/screen-component.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import { createScreenStatusNodes, createScreenStatusMixin } from '../../_shared/screen-status.js';
import { safeExec } from '../../../utils/safe-exec.js';
import './meal-card/meal-card.component.js';
import type { MealCard, MealCardOpenPickerEvent } from './meal-card/meal-card.component.js';
import '../meal-ingredient-picker/meal-ingredient-picker.component.js';
import type { MealIngredientPicker } from '../meal-ingredient-picker/meal-ingredient-picker.component.js';

interface PickerSession {
    card: MealCard;
    editingIndex: number | null;
}

export class HealthMealsScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private pickerSession: PickerSession | null = null;
    private focusValue: string | null = null;

    private listView!: HTMLElement;
    private listEl!: HTMLElement;
    private pickerHost!: HTMLElement;
    private picker: MealIngredientPicker | null = null;

    private statusNodes = createScreenStatusNodes();
    private statusMixin = createScreenStatusMixin(this.statusNodes.loadingNode, this.statusNodes.errorNode, this.statusNodes.retryNode);
    private readonly log = createComponentLogger('health-meals-screen');

    setLoading(): void { this.statusMixin.setLoading(); }
    setError(err: unknown): void { this.statusMixin.setError(err); }
    clearStatus(): void { this.statusMixin.clearStatus(); }

    set query(value: URLSearchParams | null) {
        this.focusValue = value?.get('focus') ?? null;
        if (this.initialized) this.applyFocus();
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Health · Meals', 'health', '/health');

        this.statusNodes.loadingNode.textContent = 'Loading meals…';
        this.statusNodes.retryNode.addEventListener('click', () => { void this.refresh(); });

        this.listView = document.createElement('div');
        this.listView.className = 'meals-container';
        const toolbar = document.createElement('div');
        toolbar.className = 'toolbar';
        const newBtn = document.createElement('button');
        newBtn.type = 'button';
        newBtn.className = 'btn-primary';
        newBtn.textContent = '+ New meal';
        newBtn.addEventListener('click', () => this.startNewMeal());
        toolbar.appendChild(newBtn);
        this.listEl = document.createElement('div');
        this.listEl.className = 'meals-list';
        this.listView.append(toolbar, this.listEl);

        this.pickerHost = document.createElement('div');
        this.pickerHost.hidden = true;

        page.content.append(
            this.statusNodes.loadingNode,
            this.statusNodes.errorNode,
            this.statusNodes.retryNode,
            this.listView,
            this.pickerHost,
        );

        // Card intents.
        this.addEventListener('meal-card-open-picker', (event: MealCardOpenPickerEvent) => {
            event.stopPropagation();
            const card = event.target as MealCard;
            this.openPicker(card, event.detail.editingIndex);
        });
        this.addEventListener('meal-card-save', (event: Event) => {
            event.stopPropagation();
            void this.handleSave(event.target as MealCard);
        });
        this.addEventListener('meal-card-delete', (event: Event) => {
            event.stopPropagation();
            void this.handleDelete(event.target as MealCard);
        });
        this.addEventListener('meal-card-cancel', (event: Event) => {
            event.stopPropagation();
            const card = event.target as MealCard;
            card.remove();
        });

        // Picker outcomes.
        this.addEventListener(HEALTH_EVENTS.ADD_INGREDIENT, (event: AddIngredientEvent) => {
            event.stopPropagation();
            this.commitPickerResult(event.detail.food_item, event.detail.amount);
        });
        this.addEventListener(HEALTH_EVENTS.PICKER_CANCEL, (event: PickerCancelEvent) => {
            event.stopPropagation();
            this.closePicker();
        });

        void this.refresh();
    }

    private async refresh(): Promise<void> {
        return safeExec(this, this.log, async () => {
            const summaries = await HealthService.listMeals();
            const detailed = await Promise.all(summaries.map((m) => HealthService.fetchMeal(m.id)));
            this.log.debug('refresh', { count: detailed.length, focus: this.focusValue });
            this.renderList(detailed);
        });
    }

    private renderList(meals: MealWithIngredients[]): void {
        this.listEl.replaceChildren();
        if (meals.length === 0) {
            const empty = document.createElement('div');
            empty.className = 'empty-state';
            empty.textContent = 'No meals yet. Tap "+ New meal" to create one.';
            this.listEl.appendChild(empty);
            return;
        }
        for (const meal of meals) {
            this.listEl.appendChild(this.createCardFromMeal(meal));
        }
        this.applyFocus();
    }

    private createCardFromMeal(meal: MealWithIngredients): MealCard {
        const card = document.createElement('meal-card') as MealCard;
        card.initialDraft = {
            id: meal.id,
            name: meal.name,
            notes: meal.notes ?? '',
            default_scale: meal.default_scale,
            ingredients: meal.ingredients.map((i) => ({ food_item: i.food_item, amount: i.amount })),
        };
        return card;
    }

    private applyFocus(): void {
        if (!this.focusValue) return;
        const card = this.listEl.querySelector(`meal-card[data-draft-id="${CSS.escape(this.focusValue)}"]`) as MealCard | null;
        if (card) {
            card.expand();
            card.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
    }

    private startNewMeal(): void {
        const card = document.createElement('meal-card') as MealCard;
        card.initialDraft = { name: '', notes: '', default_scale: 1, ingredients: [] };
        this.listEl.prepend(card);
    }

    private openPicker(card: MealCard, editingIndex: number | null): void {
        this.log.debug('openPicker', { draftId: card.dataset.draftId ?? '(new)', editingIndex });
        this.pickerSession = { card, editingIndex };
        this.pickerHost.replaceChildren();
        this.picker = document.createElement('meal-ingredient-picker') as MealIngredientPicker;
        this.picker.title = editingIndex === null ? 'Add ingredient' : 'Edit ingredient';
        if (editingIndex !== null) {
            const ing = card.getDraft().ingredients[editingIndex];
            if (ing) this.picker.showLibraryItem(ing.food_item, ing.amount);
        }
        this.pickerHost.appendChild(this.picker);
        this.listView.hidden = true;
        this.pickerHost.hidden = false;
    }

    private closePicker(): void {
        this.pickerSession = null;
        this.pickerHost.replaceChildren();
        this.picker = null;
        this.pickerHost.hidden = true;
        this.listView.hidden = false;
    }

    private commitPickerResult(food: NonNullable<ReturnType<MealCard['getDraft']>['ingredients'][number]>['food_item'], amount: number): void {
        const session = this.pickerSession;
        if (!session) {
            this.log.warn('picker commit with no session — dropping result', { foodItemId: food.id });
            this.closePicker();
            return;
        }
        this.log.debug('picker commit', { foodItemId: food.id, amount, editingIndex: session.editingIndex });
        session.card.setIngredient(session.editingIndex, food, amount);
        this.closePicker();
    }

    private async handleSave(card: MealCard): Promise<void> {
        const draft = card.getDraft();
        const payload: NewMealWithIngredients = {
            name: draft.name.trim(),
            notes: draft.notes.trim() || undefined,
            default_scale: draft.default_scale,
            ingredients: draft.ingredients.map((i) => ({ food_item_id: i.food_item.id, amount: i.amount })),
        };
        this.log.debug('save', { id: draft.id ?? '(new)', name: payload.name, ingredients: payload.ingredients.length, default_scale: payload.default_scale });
        return safeExec(this, this.log, async () => {
            if (draft.id) {
                await HealthService.updateMeal(draft.id, payload);
            } else {
                await HealthService.createMeal(payload);
            }
            const summaries = await HealthService.listMeals();
            const detailed = await Promise.all(summaries.map((m) => HealthService.fetchMeal(m.id)));
            this.renderList(detailed);
        });
    }

    private async handleDelete(card: MealCard): Promise<void> {
        const draft = card.getDraft();
        if (!draft.id) return;
        this.log.debug('delete', { id: draft.id, name: draft.name });
        return safeExec(this, this.log, async () => {
            await HealthService.deleteMeal(draft.id!);
            const summaries = await HealthService.listMeals();
            const detailed = await Promise.all(summaries.map((m) => HealthService.fetchMeal(m.id)));
            this.renderList(detailed);
        });
    }
}

if (!customElements.get('health-meals-screen')) {
    customElements.define('health-meals-screen', HealthMealsScreen);
}
