import stylesText from './meal-ingredient-row.css?inline';
import { cssStyleSheet } from '../../../../../utils/css.js';
import type { FoodItem } from '@motivation/shared';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <li class="row">
        <span class="name" data-role="name" title="Edit this ingredient"></span>
        <input type="number" data-role="amount" min="0.1" step="0.1">
        <span class="unit" data-role="unit"></span>
        <button class="remove" data-role="remove" type="button" aria-label="Remove ingredient">×</button>
    </li>
`;

export interface MealIngredientAmountChangeDetail { amount: number }
export type MealIngredientAmountChangeEvent = CustomEvent<MealIngredientAmountChangeDetail>;
export type MealIngredientEditEvent = CustomEvent<undefined>;
export type MealIngredientRemoveEvent = CustomEvent<undefined>;

export class MealIngredientRow extends HTMLElement {
    private foodItemValue: FoodItem | null = null;
    private amountValue = 0;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    set foodItem(value: FoodItem) {
        this.foodItemValue = value;
        this.render();
    }

    set amount(value: number) {
        this.amountValue = value;
        this.render();
    }

    /** Read the current edited amount (the input may have a newer value than the prop). */
    getAmount(): number {
        const input = this.shadowRoot?.querySelector('[data-role="amount"]') as HTMLInputElement | null;
        const parsed = input ? Number.parseFloat(input.value) : NaN;
        return Number.isFinite(parsed) && parsed > 0 ? parsed : this.amountValue;
    }

    connectedCallback(): void {
        const shadow = this.shadowRoot!;
        const name = shadow.querySelector('[data-role="name"]') as HTMLElement;
        const amount = shadow.querySelector('[data-role="amount"]') as HTMLInputElement;
        const remove = shadow.querySelector('[data-role="remove"]') as HTMLButtonElement;

        name.addEventListener('click', () => {
            this.dispatchEvent(new CustomEvent('meal-ingredient-edit', { bubbles: true, composed: true }));
        });

        amount.addEventListener('input', () => {
            const n = Number.parseFloat(amount.value);
            if (Number.isFinite(n) && n > 0) {
                this.amountValue = n;
                this.dispatchEvent(new CustomEvent('meal-ingredient-amount-change', {
                    bubbles: true,
                    composed: true,
                    detail: { amount: n },
                }));
            }
        });

        remove.addEventListener('click', () => {
            this.dispatchEvent(new CustomEvent('meal-ingredient-remove', { bubbles: true, composed: true }));
        });

        this.render();
    }

    private render(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const name = shadow.querySelector('[data-role="name"]') as HTMLElement | null;
        const amount = shadow.querySelector('[data-role="amount"]') as HTMLInputElement | null;
        const unit = shadow.querySelector('[data-role="unit"]') as HTMLElement | null;
        if (name && this.foodItemValue) name.textContent = this.foodItemValue.display_name;
        if (unit && this.foodItemValue) unit.textContent = this.foodItemValue.base_unit;
        if (amount) amount.value = String(this.amountValue);
    }
}

if (!customElements.get('meal-ingredient-row')) {
    customElements.define('meal-ingredient-row', MealIngredientRow);
}
