import stylesText from './meal-card.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';
import { formatMacro } from '../../../../utils/format-macro.js';
import { computeSnapshotMacros, type FoodItem } from '@motivation/shared';
import { createComponentLogger } from '../../../../utils/component-logger.js';
import './meal-ingredient-row/meal-ingredient-row.component.js';
import type {
    MealIngredientAmountChangeEvent,
    MealIngredientEditEvent,
    MealIngredientRemoveEvent,
    MealIngredientRow,
} from './meal-ingredient-row/meal-ingredient-row.component.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <details>
        <summary>
            <span class="summary-name" data-role="summary-name"></span>
            <span class="summary-meta" data-role="summary-meta"></span>
            <span class="summary-cal" data-role="summary-cal"></span>
        </summary>
        <div class="body">
            <div>
                <label>Name</label>
                <input type="text" data-field="name">
                <p class="form-error" data-error="name" hidden>Name is required</p>
            </div>
            <div>
                <label>Notes</label>
                <textarea data-field="notes"></textarea>
            </div>
            <div class="scale-row">
                <label>Default scale</label>
                <input type="number" data-field="default-scale" min="0.1" step="0.1">
            </div>
            <label>Ingredients</label>
            <ul class="ingredient-list" data-role="ingredient-list"></ul>
            <p class="form-error" data-error="ingredients" hidden>Add at least one ingredient</p>
            <button class="btn-secondary" data-action="add-ingredient" type="button">+ Add ingredient</button>
            <div class="actions" data-role="actions"></div>
        </div>
    </details>
`;

export interface DraftIngredient {
    food_item: FoodItem;
    amount: number;
}

export interface MealDraft {
    /** Existing server id; absent for an in-progress new meal. */
    id?: string;
    name: string;
    notes: string;
    default_scale: number;
    ingredients: DraftIngredient[];
}

export interface MealCardOpenPickerDetail { editingIndex: number | null }
export type MealCardOpenPickerEvent = CustomEvent<MealCardOpenPickerDetail>;
export type MealCardSaveEvent = CustomEvent<undefined>;
export type MealCardDeleteEvent = CustomEvent<undefined>;
export type MealCardCancelEvent = CustomEvent<undefined>;

const DELETE_CONFIRM_TIMEOUT_MS = 5000;

/**
 * One meal card. Owns the in-progress draft state (name, notes, scale,
 * ingredients) and the two-step delete affordance. The parent screen reads
 * the current draft via `getDraft()` and pushes picker results via
 * `setIngredient()`. The card never talks to the network or to the picker.
 */
export class MealCard extends HTMLElement {
    private draft: MealDraft = { name: '', notes: '', default_scale: 1, ingredients: [] };
    private armedForDelete = false;
    private disarmTimeout: ReturnType<typeof setTimeout> | null = null;
    private readonly log = createComponentLogger('meal-card');

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    /** One-shot initialization from the meals screen. Re-assignment re-renders. */
    set initialDraft(draft: MealDraft) {
        this.draft = {
            id: draft.id,
            name: draft.name,
            notes: draft.notes,
            default_scale: draft.default_scale,
            ingredients: draft.ingredients.map((i) => ({ ...i })),
        };
        if (this.draft.id) {
            this.dataset.draftId = this.draft.id;
        }
        this.render();
    }

    /** Snapshot of the current edit state — used by the screen on save. */
    getDraft(): MealDraft {
        return {
            id: this.draft.id,
            name: this.draft.name,
            notes: this.draft.notes,
            default_scale: this.draft.default_scale,
            ingredients: this.draft.ingredients.map((i) => ({ ...i })),
        };
    }

    /** Push a picker result into the draft. `editingIndex === null` appends. */
    setIngredient(editingIndex: number | null, food: FoodItem, amount: number): void {
        this.log.debug('setIngredient', {
            draftId: this.draft.id ?? '(new)',
            editingIndex,
            foodItemId: food.id,
            foodName: food.display_name,
            amount,
        });
        if (editingIndex === null) {
            this.draft.ingredients.push({ food_item: food, amount });
        } else {
            this.draft.ingredients[editingIndex] = { food_item: food, amount };
        }
        this.renderIngredients();
        this.refreshSummary();
        this.expand();
    }

    /** Open the card's <details>. Used for `?focus=` deep-linking. */
    expand(): void {
        const details = this.shadowRoot?.querySelector('details');
        if (details) details.open = true;
    }

    /** Show the inline name/ingredients errors. Returns true if valid. */
    validate(): boolean {
        const nameError = this.shadowRoot!.querySelector('[data-error="name"]') as HTMLElement;
        const ingredientsError = this.shadowRoot!.querySelector('[data-error="ingredients"]') as HTMLElement;
        const nameOk = this.draft.name.trim().length > 0;
        const ingredientsOk = this.draft.ingredients.length > 0;
        nameError.hidden = nameOk;
        ingredientsError.hidden = ingredientsOk;
        if (!nameOk || !ingredientsOk) {
            this.log.debug('validation blocked save', { draftId: this.draft.id ?? '(new)', nameOk, ingredientsOk });
        }
        return nameOk && ingredientsOk;
    }

    connectedCallback(): void {
        const shadow = this.shadowRoot!;

        const nameInput = shadow.querySelector('[data-field="name"]') as HTMLInputElement;
        const nameError = shadow.querySelector('[data-error="name"]') as HTMLElement;
        nameInput.addEventListener('input', () => {
            this.draft.name = nameInput.value;
            nameError.hidden = true;
            this.refreshSummary();
        });

        const notesInput = shadow.querySelector('[data-field="notes"]') as HTMLTextAreaElement;
        notesInput.addEventListener('input', () => { this.draft.notes = notesInput.value; });

        const scaleInput = shadow.querySelector('[data-field="default-scale"]') as HTMLInputElement;
        scaleInput.addEventListener('input', () => {
            const n = Number.parseFloat(scaleInput.value);
            if (Number.isFinite(n) && n > 0) {
                this.draft.default_scale = n;
                this.refreshSummary();
            }
        });

        const addBtn = shadow.querySelector('[data-action="add-ingredient"]') as HTMLButtonElement;
        addBtn.addEventListener('click', () => this.dispatchOpenPicker(null));

        // Ingredient row events bubble up here.
        this.addEventListener('meal-ingredient-edit', (event: MealIngredientEditEvent) => {
            event.stopPropagation();
            const idx = this.indexOfRow(event);
            if (idx !== -1) this.dispatchOpenPicker(idx);
        });
        this.addEventListener('meal-ingredient-amount-change', (event: MealIngredientAmountChangeEvent) => {
            event.stopPropagation();
            const idx = this.indexOfRow(event);
            if (idx !== -1) {
                this.draft.ingredients[idx].amount = event.detail.amount;
                this.refreshSummary();
            }
        });
        this.addEventListener('meal-ingredient-remove', (event: MealIngredientRemoveEvent) => {
            event.stopPropagation();
            const idx = this.indexOfRow(event);
            if (idx === -1) return;
            this.draft.ingredients.splice(idx, 1);
            this.renderIngredients();
            this.refreshSummary();
        });

        this.render();
    }

    disconnectedCallback(): void {
        if (this.disarmTimeout) clearTimeout(this.disarmTimeout);
    }

    private dispatchOpenPicker(editingIndex: number | null): void {
        this.dispatchEvent(new CustomEvent<MealCardOpenPickerDetail>('meal-card-open-picker', {
            bubbles: true,
            composed: true,
            detail: { editingIndex },
        }));
    }

    private indexOfRow(event: Event): number {
        // event.target is retargeted to `this` for listeners on the host; walk the
        // composed path to find the <meal-ingredient-row> that actually fired.
        const list = this.shadowRoot!.querySelector('[data-role="ingredient-list"]')!;
        const rows = Array.from(list.children);
        for (const node of event.composedPath()) {
            const idx = rows.indexOf(node as Element);
            if (idx !== -1) return idx;
        }
        return -1;
    }

    private render(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const details = shadow.querySelector('details') as HTMLDetailsElement;
        if (!this.draft.id) details.open = true;

        (shadow.querySelector('[data-field="name"]') as HTMLInputElement).value = this.draft.name;
        (shadow.querySelector('[data-field="notes"]') as HTMLTextAreaElement).value = this.draft.notes;
        (shadow.querySelector('[data-field="default-scale"]') as HTMLInputElement).value = String(this.draft.default_scale);

        this.renderIngredients();
        this.renderActions();
        this.refreshSummary();
    }

    private renderIngredients(): void {
        const list = this.shadowRoot!.querySelector('[data-role="ingredient-list"]') as HTMLElement;
        const ingredientsError = this.shadowRoot!.querySelector('[data-error="ingredients"]') as HTMLElement;
        list.replaceChildren();
        for (const ing of this.draft.ingredients) {
            const row = document.createElement('meal-ingredient-row') as MealIngredientRow;
            row.foodItem = ing.food_item;
            row.amount = ing.amount;
            list.appendChild(row);
        }
        if (this.draft.ingredients.length > 0) ingredientsError.hidden = true;
    }

    private renderActions(): void {
        const host = this.shadowRoot!.querySelector('[data-role="actions"]') as HTMLElement;
        host.replaceChildren();

        if (this.draft.id) {
            const deleteBtn = document.createElement('button');
            deleteBtn.type = 'button';
            deleteBtn.className = 'btn-secondary btn-danger';
            deleteBtn.id = 'btn-delete';
            deleteBtn.textContent = 'Delete';

            const cancelDeleteBtn = document.createElement('button');
            cancelDeleteBtn.type = 'button';
            cancelDeleteBtn.className = 'btn-secondary';
            cancelDeleteBtn.textContent = 'Cancel';
            cancelDeleteBtn.id = 'btn-cancel-delete';
            cancelDeleteBtn.hidden = true;

            const disarm = () => {
                this.armedForDelete = false;
                deleteBtn.textContent = 'Delete';
                deleteBtn.classList.remove('btn-danger-confirm');
                cancelDeleteBtn.hidden = true;
                if (this.disarmTimeout) { clearTimeout(this.disarmTimeout); this.disarmTimeout = null; }
            };

            cancelDeleteBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                disarm();
            });

            deleteBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                if (!this.armedForDelete) {
                    this.armedForDelete = true;
                    deleteBtn.textContent = 'Confirm delete';
                    deleteBtn.classList.add('btn-danger-confirm');
                    cancelDeleteBtn.hidden = false;
                    this.disarmTimeout = setTimeout(disarm, DELETE_CONFIRM_TIMEOUT_MS);
                    return;
                }
                disarm();
                this.dispatchEvent(new CustomEvent('meal-card-delete', { bubbles: true, composed: true }));
            });
            host.append(deleteBtn, cancelDeleteBtn);
        } else {
            const cancelBtn = document.createElement('button');
            cancelBtn.type = 'button';
            cancelBtn.className = 'btn-secondary';
            cancelBtn.textContent = 'Cancel';
            cancelBtn.addEventListener('click', () => {
                this.dispatchEvent(new CustomEvent('meal-card-cancel', { bubbles: true, composed: true }));
            });
            host.appendChild(cancelBtn);
        }

        const saveBtn = document.createElement('button');
        saveBtn.type = 'button';
        saveBtn.id = 'btn-save';
        saveBtn.className = 'btn-primary';
        saveBtn.textContent = this.draft.id ? 'Save changes' : 'Create meal';
        saveBtn.addEventListener('click', () => {
            if (!this.validate()) return;
            this.dispatchEvent(new CustomEvent('meal-card-save', { bubbles: true, composed: true }));
        });
        host.appendChild(saveBtn);
    }

    private refreshSummary(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const name = shadow.querySelector('[data-role="summary-name"]') as HTMLElement;
        const meta = shadow.querySelector('[data-role="summary-meta"]') as HTMLElement;
        const cal = shadow.querySelector('[data-role="summary-cal"]') as HTMLElement;
        name.textContent = this.draft.name || '(unnamed meal)';
        const count = this.draft.ingredients.length;
        meta.textContent = `${count} item${count === 1 ? '' : 's'}`;
        let total = 0;
        for (const ing of this.draft.ingredients) {
            const macros = computeSnapshotMacros(ing.food_item, ing.amount * this.draft.default_scale);
            total += macros.calories ?? 0;
        }
        cal.textContent = `${formatMacro(total)} kcal`;
    }
}

if (!customElements.get('meal-card')) {
    customElements.define('meal-card', MealCard);
}
