import stylesText from './meal-ingredient-picker.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { HealthService } from '../../../services/health.service.js';
import { OpenFoodFactsService } from '../../../services/openfoodfacts.service.js';
import type { OFFProduct } from '../../../services/openfoodfacts.service.js';
import type { FoodItem } from '@motivation/shared';
import {
    HEALTH_EVENTS,
    createPickerCancelEvent,
    type SelectLibraryItemEvent,
    type SelectOffItemEvent,
    type FoodLogBackEvent,
} from '../health-events.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import '../food-log/food-search-results.component.js';
import '../food-log/food-log-detail.component.js';
import type { FoodSearchResults } from '../food-log/food-search-results.component.js';
import type { FoodLogDetail } from '../food-log/food-log-detail.component.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <div class="picker">
        <div class="picker-header">
            <button class="btn-secondary" id="back-btn" type="button">← Back to meal</button>
            <span class="picker-title" id="title">Add ingredient</span>
        </div>

        <div id="search-view">
            <div class="search-bar">
                <input id="search-input" type="text" placeholder="Search for food…">
            </div>
            <div id="search-loading" class="loading-text" hidden>Searching…</div>
            <div id="search-error" class="error-text" hidden></div>
            <food-search-results id="results"></food-search-results>
        </div>

        <div id="detail-view" hidden>
            <food-log-detail id="detail" mode="add-ingredient"></food-log-detail>
        </div>
    </div>
`;

/**
 * Self-contained ingredient picker for the meals screen. Composes
 * `<food-search-results>` and `<food-log-detail mode="add-ingredient">`
 * directly; owns its own view-swap. Emits ADD_INGREDIENT and PICKER_CANCEL
 * upward and **stops** the internal SELECT_FOOD_LOG_BACK events at this
 * boundary so the parent never has to drive the view.
 */
export class MealIngredientPicker extends HTMLElement {
    private readonly log = createComponentLogger('meal-ingredient-picker');
    private searchTimeout: ReturnType<typeof setTimeout> | null = null;
    private searchSeq = 0;
    private offAbort: AbortController | null = null;
    private currentQuery = '';
    private titleValue = 'Add ingredient';

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    /** Optional title override for "edit ingredient" vs "add ingredient". */
    set title(value: string) {
        this.titleValue = value;
        const el = this.shadowRoot?.getElementById('title');
        if (el) el.textContent = value;
    }

    /** Open the picker with an existing food item pre-selected (edit ingredient flow). */
    showLibraryItem(item: FoodItem, initialAmount?: number): void {
        const detail = this.shadowRoot!.getElementById('detail') as FoodLogDetail;
        detail.showLibraryItem(item, initialAmount);
        this.showDetailView();
    }

    connectedCallback(): void {
        const shadow = this.shadowRoot!;
        shadow.getElementById('title')!.textContent = this.titleValue;

        const detail = shadow.getElementById('detail') as FoodLogDetail;
        detail.mode = 'add-ingredient';

        const search = shadow.getElementById('search-input') as HTMLInputElement;
        search.addEventListener('input', () => {
            if (this.searchTimeout) clearTimeout(this.searchTimeout);
            this.searchTimeout = setTimeout(() => void this.runSearch(search.value.trim()), 300);
        });
        search.addEventListener('keydown', (e: KeyboardEvent) => {
            if (e.key === 'Enter') {
                if (this.searchTimeout) clearTimeout(this.searchTimeout);
                void this.runSearch(search.value.trim());
            }
        });

        shadow.getElementById('back-btn')!.addEventListener('click', () => {
            const detailView = shadow.getElementById('detail-view')!;
            if (detailView.hidden) {
                this.dispatchEvent(createPickerCancelEvent());
            } else {
                this.showSearchView();
            }
        });

        // Stop these at this boundary — the picker owns its view-swap.
        // Without stopPropagation they would bubble out of the meals screen
        // and be picked up by any listener up the tree. Listening on `this`
        // (the host) rather than the shadow root so the typed
        // HTMLElementEventMap overloads pick the right CustomEvent shapes.
        this.addEventListener(HEALTH_EVENTS.SELECT_LIBRARY_ITEM, (event: SelectLibraryItemEvent) => {
            event.stopPropagation();
            this.log.debug('select library item', { foodItemId: event.detail.id, name: event.detail.display_name });
            const detail = shadow.getElementById('detail') as FoodLogDetail;
            detail.showLibraryItem(event.detail);
            this.showDetailView();
        });
        this.addEventListener(HEALTH_EVENTS.SELECT_OFF_ITEM, (event: SelectOffItemEvent) => {
            event.stopPropagation();
            this.log.debug('select OFF item', { barcode: event.detail.barcode, name: event.detail.product_name });
            const detail = shadow.getElementById('detail') as FoodLogDetail;
            detail.showProduct(event.detail);
            this.showDetailView();
        });
        this.addEventListener(HEALTH_EVENTS.FOOD_LOG_BACK, (event: FoodLogBackEvent) => {
            event.stopPropagation();
            this.log.debug('back to search');
            this.showSearchView();
        });

        search.focus();
    }

    disconnectedCallback(): void {
        if (this.searchTimeout) clearTimeout(this.searchTimeout);
        this.offAbort?.abort();
    }

    private showDetailView(): void {
        const shadow = this.shadowRoot!;
        shadow.getElementById('search-view')!.hidden = true;
        shadow.getElementById('detail-view')!.hidden = false;
    }

    private showSearchView(): void {
        const shadow = this.shadowRoot!;
        shadow.getElementById('search-view')!.hidden = false;
        shadow.getElementById('detail-view')!.hidden = true;
    }

    private async runSearch(query: string): Promise<void> {
        if (query.length < 2) return;
        this.currentQuery = query;
        const shadow = this.shadowRoot!;
        const results = shadow.getElementById('results') as FoodSearchResults;
        const loadingEl = shadow.getElementById('search-loading')!;
        const errorEl = shadow.getElementById('search-error')!;
        const seq = ++this.searchSeq;

        this.offAbort?.abort();
        this.offAbort = new AbortController();
        loadingEl.hidden = false;
        errorEl.hidden = true;
        results.clear();

        let libraryFailed = false;
        let offFailed = false;

        const finalize = (libraryCount: number, offCount: number) => {
            if (seq !== this.searchSeq) return;
            loadingEl.hidden = true;
            this.log.debug('search done', { query, libraryCount, offCount, libraryFailed, offFailed });
            if (libraryFailed && offFailed) {
                errorEl.textContent = 'Search failed. Please try again.';
                errorEl.hidden = false;
                return;
            }
            if (libraryCount === 0 && offCount === 0) {
                results.showEmpty('No products found');
            }
        };

        let libraryCount = 0;
        let offCount = 0;
        let libraryDone = false;
        let offDone = false;

        const tryFinalize = () => {
            if (libraryDone && offDone) finalize(libraryCount, offCount);
        };

        void HealthService.searchFoodItems(query)
            .then((items) => {
                if (seq !== this.searchSeq) return;
                libraryCount = items.length;
                libraryDone = true;
                if (items.length > 0) results.libraryItems = items;
                tryFinalize();
            })
            .catch((err) => {
                if (seq !== this.searchSeq) return;
                libraryFailed = true;
                libraryDone = true;
                this.log.warn('Library search failed', err);
                tryFinalize();
            });

        void OpenFoodFactsService.searchFood(query, { signal: this.offAbort.signal, page: 1 })
            .then((page) => {
                if (seq !== this.searchSeq) return;
                offCount = page.items.length;
                offDone = true;
                if (page.items.length > 0) {
                    results.offItems = page.items;
                    results.showLoadMore = page.page < page.pageCount;
                }
                tryFinalize();
            })
            .catch((err) => {
                if (seq !== this.searchSeq) return;
                if (err instanceof Error && err.name === 'AbortError') return;
                offFailed = true;
                offDone = true;
                this.log.warn('OFF search failed', err);
                tryFinalize();
            });
    }
}

if (!customElements.get('meal-ingredient-picker')) {
    customElements.define('meal-ingredient-picker', MealIngredientPicker);
}
